        # Find index of minimum element in unsorted portion
        min_index = i
        for j in range(i + 1, n):
            if arr[j] < arr[min_index]:
                min_index = j

        # Swap minimum element into its sorted position
        arr[i], arr[min_index] = arr[min_index], arr[i]

